def cal_priority(status, num_neighboring_machine, processing_time, start_time, delivery_time, available_time, num_neighboring_operation, utilization, processing_tm):
    slack = delivery_time - available_time - processing_time
    if slack < 0:
        # Negative slack: prioritize by magnitude of lateness and machine contention
        priority = -slack * (num_neighboring_machine + 1)
    else:
        # Positive slack: shorter delivery time and higher utilization get lower priority
        denominator = (num_neighboring_machine + 1)
        if denominator == 0:
            denominator = 1
        priority = (delivery_time + processing_time) * (1 + utilization) / denominator
    result = priority
    return priority

def cal_priority(status, num_neighboring_machine, processing_time, start_time, delivery_time, available_time, num_neighboring_operation, utilization, processing_tm):
    if processing_time == 0:
        slack_ratio = float('inf')
    else:
        slack_ratio = (delivery_time - available_time) / processing_time

    # Use normalized processing time on current machine (processing_tm)
    norm_processing = processing_tm if processing_tm != 0 else processing_time

    # Utilization penalty only when machine queue length exceeds threshold (e.g., num_neighboring_machine > 2)
    threshold = 2
    if num_neighboring_machine > threshold:
        util_penalty = 1 + utilization
    else:
        util_penalty = 1.0

    # Determine priority based on slack
    if slack_ratio < 0:
        # Negative slack: prioritize by magnitude of lateness and machine contention
        priority = -slack_ratio * (num_neighboring_machine + 1)
    else:
        # Positive slack: use dynamic slack ratio and normalized processing time
        denominator = (num_neighboring_machine + 1)
        if denominator == 0:
            denominator = 1
        priority = (delivery_time + norm_processing) * util_penalty / denominator

    result = priority
    return priority

